import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { TEMPLATES, TARGET_ROLES, ROLE_SKILLS, COLOR_PRESETS, FONT_OPTIONS } from '../data/staticData';
import {
  Edit3, Palette, Globe, Download, Target, ChevronDown, Check,
  ExternalLink, ArrowLeft, BarChart3, Sparkles
} from 'lucide-react';
import './PreviewPage.css';

const ATS_WEIGHTS = { summary: 15, skills: 30, workExperience: 25, education: 15, projects: 10, certifications: 5 };

const calcATSScore = (resumeData, roleId) => {
  if (!roleId || roleId === 'other') return null;
  const roleSkills = ROLE_SKILLS[roleId] || [];
  const userSkills = (resumeData.skills || []).map(s => s.toLowerCase());
  const skillMatch = roleSkills.filter(s => userSkills.includes(s.toLowerCase())).length / roleSkills.length;

  let score = 0;
  if (resumeData.summary?.length > 50) score += ATS_WEIGHTS.summary;
  else if (resumeData.summary?.length > 0) score += ATS_WEIGHTS.summary * 0.5;
  score += ATS_WEIGHTS.skills * skillMatch;
  if ((resumeData.workExperience || []).length > 0) score += ATS_WEIGHTS.workExperience * Math.min((resumeData.workExperience.length / 2), 1);
  if ((resumeData.education || []).length > 0) score += ATS_WEIGHTS.education;
  if ((resumeData.projects || []).length > 0) score += ATS_WEIGHTS.projects * Math.min((resumeData.projects.length / 2), 1);
  if ((resumeData.certifications || []).length > 0) score += ATS_WEIGHTS.certifications;
  return Math.round(Math.min(score, 100));
};

const ResumePreview = ({ data, style }) => {
  const { name, professionalTitle, email, phone, city, linkedin, github, summary, education, workExperience, skills, projects, certifications, additionalInfo } = data;
  return (
    <div className="resume-doc" style={{ fontFamily: style.font, '--resume-accent': style.color }}>
      <div className="resume-header">
        <h1 className="resume-name">{name || 'Your Name'}</h1>
        <p className="resume-title">{professionalTitle || 'Professional Title'}</p>
        <div className="resume-contact">
          {email && <span>{email}</span>}
          {phone && <span>•</span>}
          {phone && <span>{phone}</span>}
          {city && <span>•</span>}
          {city && <span>{city}</span>}
          {linkedin && <span>•</span>}
          {linkedin && <span>{linkedin}</span>}
          {github && <span>•</span>}
          {github && <span>{github}</span>}
        </div>
      </div>
      {summary && (
        <div className="resume-section">
          <h2 className="resume-section-title">Professional Summary</h2>
          <p className="resume-text">{summary}</p>
        </div>
      )}
      {(skills || []).length > 0 && (
        <div className="resume-section">
          <h2 className="resume-section-title">Skills</h2>
          <div className="resume-skills-list">
            {skills.map(s => <span key={s} className="resume-skill-tag">{s}</span>)}
          </div>
        </div>
      )}
      {(workExperience || []).length > 0 && (
        <div className="resume-section">
          <h2 className="resume-section-title">Work Experience</h2>
          {workExperience.map((exp, i) => (
            <div key={i} className="resume-entry">
              <div className="resume-entry-header">
                <div>
                  <strong>{exp.title}</strong>
                  <span> — {exp.company}</span>
                  {exp.location && <span>, {exp.location}</span>}
                </div>
                <span className="resume-date">{exp.duration}</span>
              </div>
              {exp.description && <p className="resume-desc">{exp.description}</p>}
            </div>
          ))}
        </div>
      )}
      {(education || []).length > 0 && (
        <div className="resume-section">
          <h2 className="resume-section-title">Education</h2>
          {education.map((edu, i) => (
            <div key={i} className="resume-entry">
              <div className="resume-entry-header">
                <div>
                  <strong>{edu.degree}</strong>
                  <span> — {edu.institution}</span>
                  {edu.gpa && <span> | {edu.gpa}</span>}
                </div>
                <span className="resume-date">{edu.duration}</span>
              </div>
            </div>
          ))}
        </div>
      )}
      {(projects || []).length > 0 && (
        <div className="resume-section">
          <h2 className="resume-section-title">Projects</h2>
          {projects.map((p, i) => (
            <div key={i} className="resume-entry">
              <div className="resume-entry-header">
                <div>
                  <strong>{p.name}</strong>
                  {p.tech && <span> | {p.tech}</span>}
                </div>
                {p.link && <a href={p.link} className="resume-link" target="_blank" rel="noreferrer"><ExternalLink size={12} /></a>}
              </div>
              {p.description && <p className="resume-desc">{p.description}</p>}
            </div>
          ))}
        </div>
      )}
      {(certifications || []).length > 0 && (
        <div className="resume-section">
          <h2 className="resume-section-title">Certifications</h2>
          {certifications.map((c, i) => (
            <div key={i} className="resume-entry">
              <div className="resume-entry-header">
                <div><strong>{c.name}</strong>{c.issuer && <span> — {c.issuer}</span>}</div>
                <span className="resume-date">{c.date}</span>
              </div>
            </div>
          ))}
        </div>
      )}
      {additionalInfo && (
        <div className="resume-section">
          <h2 className="resume-section-title">Additional Information</h2>
          <p className="resume-text">{additionalInfo}</p>
        </div>
      )}
    </div>
  );
};

const PreviewPage = () => {
  const navigate = useNavigate();
  const { resumeData, resumeStyle, setResumeStyle, selectedTemplate, targetRole, setTargetRole, jobDescription, setJobDescription } = useApp();
  const [activeTab, setActiveTab] = useState('preview');
  const [showPortfolioModal, setShowPortfolioModal] = useState(false);
  const [portfolioPublished, setPortfolioPublished] = useState(false);
  const [jobDescInput, setJobDescInput] = useState(jobDescription);

  const atsScore = calcATSScore(resumeData, targetRole);
  const roleSkills = ROLE_SKILLS[targetRole] || [];
  const userSkills = (resumeData.skills || []).map(s => s.toLowerCase());
  const missingSkills = roleSkills.filter(s => !userSkills.includes(s.toLowerCase())).slice(0, 8);

  const scoreColor = atsScore >= 75 ? 'var(--success)' : atsScore >= 50 ? 'var(--warning)' : 'var(--error)';
  const scoreLabel = atsScore >= 75 ? 'Excellent' : atsScore >= 50 ? 'Good' : 'Needs Improvement';

  const circumference = 2 * Math.PI * 50;
  const dashOffset = atsScore != null ? circumference - (atsScore / 100) * circumference : circumference;

  return (
    <div className="preview-page">
      <div className="container">
        {/* Header */}
        <div className="preview-header">
          <button className="btn-ghost back-btn" onClick={() => navigate('/builder')}>
            <ArrowLeft size={16} /> Back to Builder
          </button>
          <div className="preview-tabs">
            <button className={`preview-tab ${activeTab === 'preview' ? 'active' : ''}`} onClick={() => setActiveTab('preview')}>
              <Sparkles size={15} /> Preview
            </button>
            <button className={`preview-tab ${activeTab === 'ats' ? 'active' : ''}`} onClick={() => setActiveTab('ats')}>
              <Target size={15} /> ATS Score
            </button>
          </div>
          <div className="preview-actions">
            <button className="btn-secondary" onClick={() => setShowPortfolioModal(true)}>
              <Globe size={16} /> Web Portfolio
            </button>
            <button className="btn-primary" onClick={() => window.print()}>
              <Download size={16} /> Export PDF
            </button>
          </div>
        </div>

        {/* PREVIEW TAB */}
        {activeTab === 'preview' && (
          <div className="preview-layout">
            {/* Edit panel */}
            <aside className="edit-panel">
              <div className="edit-section">
                <div className="edit-section-title"><Edit3 size={15} /> Edit</div>
                <button className="edit-btn" onClick={() => navigate('/builder')}>Edit Resume Data</button>
                <button className="edit-btn" onClick={() => navigate('/templates')}>Change Template</button>
              </div>
              <div className="edit-section">
                <div className="edit-section-title"><Palette size={15} /> Style</div>
                <div className="style-row">
                  <span className="style-label">Accent Color</span>
                  <div className="color-presets">
                    {COLOR_PRESETS.map(c => (
                      <button key={c} className={`color-dot ${resumeStyle.color === c ? 'active' : ''}`}
                        style={{ background: c }}
                        onClick={() => setResumeStyle(prev => ({ ...prev, color: c }))}>
                        {resumeStyle.color === c && <Check size={10} />}
                      </button>
                    ))}
                  </div>
                </div>
                <div className="style-row">
                  <span className="style-label">Font</span>
                  <select className="form-input style-select"
                    value={resumeStyle.font}
                    onChange={e => setResumeStyle(prev => ({ ...prev, font: e.target.value }))}>
                    {FONT_OPTIONS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
                  </select>
                </div>
              </div>
            </aside>

            {/* Resume preview */}
            <div className="resume-preview-wrap">
              <div className="preview-note">
                <Sparkles size={13} /> This is how your resume will look. Export as PDF to download.
              </div>
              <div className="resume-sheet-wrap">
                <ResumePreview data={resumeData} style={resumeStyle} />
              </div>
            </div>
          </div>
        )}

        {/* ATS SCORE TAB */}
        {activeTab === 'ats' && (
          <div className="ats-tab animate-fadeIn">
            <div className="ats-top-grid">
              {/* Role selector */}
              <div className="card ats-role-card">
                <h3 className="ats-card-title"><Target size={18} /> Target Role</h3>
                <div className="role-selector">
                  {TARGET_ROLES.map(role => (
                    <button key={role.id}
                      className={`role-btn ${targetRole === role.id ? 'active' : ''}`}
                      onClick={() => setTargetRole(role.id)}>
                      {role.label}
                      {targetRole === role.id && <Check size={13} />}
                    </button>
                  ))}
                </div>
                {targetRole === 'other' && (
                  <div className="form-group" style={{ marginTop: 16 }}>
                    <label className="form-label">Paste Job Description</label>
                    <textarea className="form-input" rows={6}
                      placeholder="Paste the full job description here to get an accurate ATS score..."
                      value={jobDescInput}
                      onChange={e => { setJobDescInput(e.target.value); setJobDescription(e.target.value); }} />
                  </div>
                )}
              </div>

              {/* Score display */}
              <div className="card ats-score-card">
                <h3 className="ats-card-title"><BarChart3 size={18} /> ATS Score</h3>
                {atsScore != null ? (
                  <div className="score-display">
                    <div className="score-ring-wrap">
                      <svg viewBox="0 0 120 120" className="score-ring-svg">
                        <circle cx="60" cy="60" r="50" fill="none" stroke="var(--border)" strokeWidth="10"/>
                        <circle cx="60" cy="60" r="50" fill="none" stroke={scoreColor} strokeWidth="10"
                          strokeDasharray={circumference} strokeDashoffset={dashOffset}
                          strokeLinecap="round" transform="rotate(-90 60 60)"
                          style={{ transition: 'stroke-dashoffset 1s ease' }}/>
                      </svg>
                      <div className="score-ring-num">
                        <span className="score-big" style={{ color: scoreColor }}>{atsScore}</span>
                        <span className="score-denom">/100</span>
                      </div>
                    </div>
                    <div className="score-label-badge" style={{ background: `${scoreColor}20`, color: scoreColor }}>
                      {scoreLabel}
                    </div>
                    <div className="score-breakdown">
                      {[
                        { label: 'Skills Match', val: Math.round(((roleSkills.filter(s => userSkills.includes(s.toLowerCase())).length / Math.max(roleSkills.length, 1)) * 100)) },
                        { label: 'Summary', val: resumeData.summary?.length > 50 ? 100 : resumeData.summary?.length > 0 ? 50 : 0 },
                        { label: 'Experience', val: Math.min(((resumeData.workExperience || []).length / 2) * 100, 100) },
                        { label: 'Projects', val: Math.min(((resumeData.projects || []).length / 2) * 100, 100) },
                      ].map(item => (
                        <div key={item.label} className="breakdown-row">
                          <span>{item.label}</span>
                          <div className="breakdown-bar"><div style={{ width: `${item.val}%`, background: scoreColor }} /></div>
                          <span>{Math.round(item.val)}%</span>
                        </div>
                      ))}
                    </div>
                  </div>
                ) : (
                  <div className="no-score-msg">
                    <Target size={36} className="no-score-icon" />
                    <p>Select a target role to see your ATS score</p>
                  </div>
                )}
              </div>
            </div>

            {/* Missing skills */}
            {targetRole && targetRole !== 'other' && missingSkills.length > 0 && (
              <div className="card missing-skills-card animate-fadeIn">
                <h3 className="ats-card-title">
                  <Sparkles size={18} /> Recommended Skills to Add
                </h3>
                <p className="missing-skills-subtitle">
                  Adding these skills to your resume could significantly boost your ATS score for <strong>{TARGET_ROLES.find(r => r.id === targetRole)?.label}</strong> roles:
                </p>
                <div className="missing-skills-grid">
                  {missingSkills.map(skill => (
                    <div key={skill} className="missing-skill-item">
                      <span className="missing-dot" />
                      {skill}
                    </div>
                  ))}
                </div>
                <p className="missing-skills-note">
                  💡 Tip: Go to the <button className="inline-link" onClick={() => navigate('/builder')}>Resume Builder</button> to add these skills.
                </p>
              </div>
            )}
          </div>
        )}
      </div>

      {/* PORTFOLIO MODAL */}
      {showPortfolioModal && (
        <div className="modal-overlay" onClick={() => setShowPortfolioModal(false)}>
          <div className="modal-box animate-fadeInUp" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2 className="modal-title"><Globe size={20} /> Generate Web Portfolio</h2>
              <button className="modal-close" onClick={() => setShowPortfolioModal(false)}>✕</button>
            </div>
            <p className="modal-subtitle">
              Your web portfolio will be generated using your resume data and the template you selected.
            </p>
            <div className="portfolio-options">
              <div className="portfolio-info-row">
                <span>Template:</span>
                <strong>{TEMPLATES.find(t => t.id === selectedTemplate)?.name || 'Classic Professional'}</strong>
              </div>
              <div className="portfolio-info-row">
                <span>Name:</span>
                <strong>{resumeData.name || 'Your Name'}</strong>
              </div>
              <div className="portfolio-info-row">
                <span>Role:</span>
                <strong>{resumeData.professionalTitle || 'Professional Title'}</strong>
              </div>
            </div>
            {!portfolioPublished ? (
              <div className="modal-actions">
                <button className="btn-secondary" onClick={() => setShowPortfolioModal(false)}>Cancel</button>
                <button className="btn-primary" onClick={() => setPortfolioPublished(true)}>
                  <Globe size={16} /> Publish Portfolio
                </button>
              </div>
            ) : (
              <div className="portfolio-published animate-fadeIn">
                <div className="published-icon">🎉</div>
                <h3>Portfolio Published!</h3>
                <p>Your portfolio is live at:</p>
                <div className="portfolio-url">
                  skillfolio.app/{(resumeData.name || 'yourname').toLowerCase().replace(/\s/g, '-')}
                </div>
                <button className="btn-primary" onClick={() => setShowPortfolioModal(false)}>Done</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default PreviewPage;
